1	/**
2	 * Core types for the media pool module.
3	 * Manages audio file storage, decoded buffers, and waveform peak data.
4	 */
5	
6	export type AudioFormat = "wav" | "mp3" | "ogg" | "flac";
7	
8	/** Immutable reference to a decoded audio source in the media pool. */
9	export type AudioSourceHandle = {
10	  readonly id: string;
11	  readonly name: string;
12	  readonly format: AudioFormat;
13	  readonly sampleRate: number;
14	  readonly channels: number;
15	  readonly durationSeconds: number;
16	  readonly fileSizeBytes: number;
17	  readonly createdAt: number;
18	};
19	
20	/** Min/max peak pairs for waveform rendering at a given resolution. */
21	export type WaveformPeaks = {
22	  readonly sourceId: string;
23	  readonly samplesPerPeak: number;
24	  /** Interleaved [min0, max0, min1, max1, ...] */
25	  readonly peaks: Float32Array;
26	  /** Number of min/max pairs */
27	  readonly length: number;
28	};
29	
30	/** Discriminated error types for media pool operations. */
31	export type DecodeError = {
32	  readonly kind: "decode-failed";
33	  readonly fileName: string;
34	  readonly format: string;
35	};
36	
37	export type StorageFullError = {
38	  readonly kind: "storage-full";
39	  readonly fileName: string;
40	};
41	
42	export type FileTooLargeError = {
43	  readonly kind: "file-too-large";
44	  readonly fileName: string;
45	  readonly sizeBytes: number;
46	  readonly limitBytes: number;
47	};
48	
49	export type ValidationError = {
50	  readonly kind: "unsupported-format";
51	  readonly fileName: string;
52	  readonly detectedBytes: string;
53	};
54	
55	export type MediaPoolError =
56	  | DecodeError
57	  | StorageFullError
58	  | FileTooLargeError
59	  | ValidationError;
60	
61	/** Result type for decode operations. */
62	export type DecodeResult =
63	  | {
64	      readonly ok: true;
65	      readonly handle: AudioSourceHandle;
66	      readonly buffer: AudioBuffer;
67	    }
68	  | { readonly ok: false; readonly error: MediaPoolError };
69	
70	/** The media pool manager interface. */
71	export type MediaPool = {
72	  importFile(file: File): Promise<DecodeResult>;
73	  getSource(id: string): AudioSourceHandle | undefined;
74	  getAudioBuffer(id: string): Promise<AudioBuffer | undefined>;
75	  getPeaks(
76	    id: string,
77	    samplesPerPeak: number,
78	  ): Promise<WaveformPeaks | undefined>;
79	  listSources(): readonly AudioSourceHandle[];
80	  removeSource(id: string): Promise<void>;
81	  readonly count: number;
82	  init(): Promise<void>;
83	};
