22	function DawShellInner(): React.JSX.Element {
23	  const registry = useMemo(() => new CommandRegistry(), []);
24	  const shortcuts = useMemo(() => new ShortcutMap(), []);
25	  const pool = useMediaPool();
26	  const undoManager = useMemo(() => createUndoManager(), []);
27	  const { saveNow, recoveryWarnings } = useSessionPersistence(defaultStorage);
28	  const [dismissed, setDismissed] = useState(false);
29	  const showRecovery = !dismissed && recoveryWarnings.length > 0;
30	
31	  const stableSaveNow = useCallback(() => saveNow(), [saveNow]);
32	
33	  useTransportShortcuts(registry, shortcuts);
34	  useSessionShortcuts(registry, shortcuts, undoManager, stableSaveNow);
35	  useKeyboardShortcuts(registry, shortcuts);
36	
37	  return (
38	    <div
39	      data-testid="daw-shell"
40	      style={{
41	        display: "flex",
42	        flexDirection: "column",
43	        height: "100vh",
44	        backgroundColor: "var(--color-black)",
45	      }}
46	    >
47	      <Toolbar />
48	      <div
49	        style={{
50	          display: "flex",
51	          flexDirection: "column",
52	          flex: 1,
53	          overflow: "hidden",
54	        }}
55	      >
56	        <ArrangementPanel />
57	        <MixerPanel />
58	        <div style={{ display: "flex", overflow: "hidden" }}>
59	          <div style={{ flex: 1 }}>
60	            <InstrumentPanel />
61	          </div>
62	          <div style={{ flex: 1 }}>
63	            <MediaPoolPanel pool={pool} />
64	          </div>
65	        </div>
66	      </div>
67	      <RecoveryDialog
68	        open={showRecovery}
69	        warnings={recoveryWarnings}
70	        onAccept={() => {
71	          setDismissed(true);
72	        }}
73	        onDiscard={() => {
74	          hydrateStore(createDefaultSession());
75	          setDismissed(true);
76	        }}
77	      />
78	    </div>
79	  );
80	}
