        duration = newEnd - startTime;
      }

      return {
        clips: {
          ...state.clips,
          [id]: { ...clip, startTime, sourceOffset, duration },
        },
      };
    });
  },

  duplicateClip: (id: string): string | undefined => {
    const state = get();
    const clip = state.clips[id];
    if (!clip) return undefined;

