1	import type { UndoCommand } from "./undo-command";
2	
3	export type UndoCommandDeserializer = (
4	  data: Record<string, unknown>,
5	) => UndoCommand;
6	
7	export class UndoCommandRegistry {
8	  private deserializers = new Map<string, UndoCommandDeserializer>();
9	
10	  register(type: string, deserializer: UndoCommandDeserializer): void {
11	    this.deserializers.set(type, deserializer);
12	  }
13	
14	  unregister(type: string): void {
15	    this.deserializers.delete(type);
16	  }
17	
18	  deserialize(
19	    type: string,
20	    data: Record<string, unknown>,
21	  ): UndoCommand | undefined {
22	    const fn = this.deserializers.get(type);
23	    if (fn === undefined) return undefined;
24	    return fn(data);
25	  }
26	
27	  has(type: string): boolean {
28	    return this.deserializers.has(type);
29	  }
30	}
