10	// Stored meta from the loaded session, preserved across auto-saves
11	let sessionMeta: { name: string; createdAt: number } = {
12	  name: "Untitled",
13	  createdAt: Date.now(),
14	};
15	
16	function storeToSession(): SessionSchema {
17	  const state = useDawStore.getState();
18	  return {
19	    version: SESSION_VERSION,
20	    meta: {
21	      name: sessionMeta.name,
22	      createdAt: sessionMeta.createdAt,
23	      updatedAt: Date.now(),
24	    },
25	    transport: {
