36	export function hydrateStore(session: SessionSchema): void {
37	  sessionMeta = {
38	    name: session.meta.name,
39	    createdAt: session.meta.createdAt,
40	  };
41	  useDawStore.setState({
42	    bpm: session.transport.bpm,
43	    loopEnabled: session.transport.loopEnabled,
44	    loopStart: session.transport.loopStart,
45	    loopEnd: session.transport.loopEnd,
46	  });
