49	type SessionPersistenceResult = {
50	  saving: boolean;
51	  dirty: boolean;
52	  saveNow: () => Promise<void>;
53	  recoveryWarnings: string[];
54	};
55	
56	export function useSessionPersistence(
57	  storage: SessionStorage,
58	): SessionPersistenceResult {
59	  const [recoveryWarnings, setRecoveryWarnings] = useState<string[]>([]);
60	  const [saving, setSaving] = useState(false);
61	  const loadedRef = useRef(false);
62	
63	  const saveQueue = useMemo(() => createSaveQueue(storage), [storage]);
64	
65	  const autoSave = useMemo(
66	    () => createAutoSave(() => JSON.stringify(storeToSession()), saveQueue),
67	    [saveQueue],
68	  );
69	
70	  // Load session from storage on mount (draft-first for crash safety)
71	  useEffect(() => {
72	    if (loadedRef.current) return;
73	    loadedRef.current = true;
74	
75	    void (async (): Promise<void> => {
76	      // Check draft first — a crash between putDraft and putCurrent
77	      // means the draft is the most recent write attempt
78	      const draft = await storage.getDraft();
79	      const raw = draft ?? (await storage.getCurrent());
80	      if (raw !== undefined) {
81	        const result = recoverSession(raw);
82	        hydrateStore(result.session);
83	        if (draft !== undefined) {
84	          result.warnings.push(
85	            "Recovered from unsaved draft (possible crash recovery)",
86	          );
87	        }
88	        if (result.warnings.length > 0) {
89	          setRecoveryWarnings(result.warnings);
90	        }
91	      }
92	    })();
93	  }, [storage]);
94	
95	  // Start auto-save and subscribe to store changes
96	  useEffect(() => {
97	    autoSave.start();
98	
99	    const unsub = useDawStore.subscribe(() => {
100	      autoSave.notifyChange();
101	    });
102	
103	    return () => {
104	      autoSave.stop();
105	      unsub();
106	    };
107	  }, [autoSave]);
108	
109	  const saveNow = useCallback(async (): Promise<void> => {
110	    setSaving(true);
