37	export function hydrateStore(session: SessionSchema): void {
38	  sessionMeta = {
39	    name: session.meta.name,
40	    createdAt: session.meta.createdAt,
41	  };
42	  const clips: Record<string, (typeof session.clips)[number]> = {};
43	  for (const clip of session.clips) {
44	    clips[clip.id] = clip;
45	  }
46	
47	  useDawStore.setState({
48	    bpm: session.transport.bpm,
49	    loopEnabled: session.transport.loopEnabled,
50	    loopStart: session.transport.loopStart,
51	    loopEnd: session.transport.loopEnd,
52	    tracks: session.tracks,
53	    clips,
