57	type SessionPersistenceResult = {
58	  saving: boolean;
59	  dirty: boolean;
60	  saveNow: () => Promise<void>;
61	  recoveryWarnings: string[];
62	};
63	
64	export function useSessionPersistence(
65	  storage: SessionStorage,
66	): SessionPersistenceResult {
67	  const [recoveryWarnings, setRecoveryWarnings] = useState<string[]>([]);
68	  const [saving, setSaving] = useState(false);
69	  const loadedRef = useRef(false);
70	
71	  const saveQueue = useMemo(() => createSaveQueue(storage), [storage]);
72	
73	  const autoSave = useMemo(
74	    () => createAutoSave(() => JSON.stringify(storeToSession()), saveQueue),
75	    [saveQueue],
76	  );
77	
78	  // Load session from storage on mount (draft-first for crash safety)
79	  useEffect(() => {
80	    if (loadedRef.current) return;
81	    loadedRef.current = true;
82	
83	    void (async (): Promise<void> => {
84	      // Check draft first — a crash between putDraft and putCurrent
85	      // means the draft is the most recent write attempt
86	      const draft = await storage.getDraft();
87	      const raw = draft ?? (await storage.getCurrent());
88	      if (raw !== undefined) {
89	        const result = recoverSession(raw);
90	        hydrateStore(result.session);
91	        if (draft !== undefined) {
92	          result.warnings.push(
93	            "Recovered from unsaved draft (possible crash recovery)",
94	          );
95	        }
96	        if (result.warnings.length > 0) {
97	          setRecoveryWarnings(result.warnings);
98	        }
99	      }
100	    })();
101	  }, [storage]);
102	
103	  // Start auto-save and subscribe to store changes
104	  useEffect(() => {
105	    autoSave.start();
106	
107	    const unsub = useDawStore.subscribe(() => {
108	      autoSave.notifyChange();
109	    });
110	
111	    return () => {
112	      autoSave.stop();
113	      unsub();
114	    };
115	  }, [autoSave]);
116	
117	  const saveNow = useCallback(async (): Promise<void> => {
118	    setSaving(true);
119	    await autoSave.saveNow();
120	    await saveQueue.flush();
121	    setSaving(false);
122	  }, [autoSave, saveQueue]);
123	
124	  return {
125	    saving,
126	    dirty: autoSave.dirty,
127	    saveNow,
128	    recoveryWarnings,
129	  };
130	}
