68	export const useDawStore = create<DawStore>()((set, get) => ({
69	  // Transport defaults
70	  transportState: "stopped",
71	  bpm: 120,
72	  cursorSeconds: 0,
73	  loopEnabled: false,
74	  loopStart: 0,
75	  loopEnd: 0,
76	
77	  // Engine defaults
78	  engineStatus: "uninitialized",
79	
80	  // Track & clip defaults
81	  tracks: [],
82	  clips: {},
83	  selectedTrackIds: [],
84	  selectedClipIds: [],
85	
86	  // Transport actions
87	  play: () => {
88	    set({ transportState: "playing" });
89	  },
90	  pause: () => {
91	    set({ transportState: "paused" });
92	  },
93	  stop: () => {
94	    set({ transportState: "stopped", cursorSeconds: 0 });
95	  },
96	  setBpm: (bpm: number) => {
97	    const clamped = Math.min(999, Math.max(20, bpm));
98	    if (!Number.isFinite(clamped)) return;
99	    set({ bpm: clamped });
100	  },
101	  setCursor: (seconds: number) => {
102	    set({ cursorSeconds: seconds });
103	  },
104	  setLoop: (enabled: boolean, start?: number, end?: number) => {
105	    set((state) => ({
106	      loopEnabled: enabled,
107	      loopStart: start ?? state.loopStart,
108	      loopEnd: end ?? state.loopEnd,
109	    }));
110	  },
111	
112	  // Engine actions
113	  setEngineStatus: (status: AudioEngineStatus) => {
114	    set({ engineStatus: status });
115	  },
116	
117	  // Track actions
118	  addTrack: (track: TrackModel, index?: number) => {
119	    set((state) => {
120	      const next = [...state.tracks];
121	      if (index !== undefined) {
122	        next.splice(index, 0, track);
123	      } else {
124	        next.push(track);
125	      }
126	      return { tracks: next };
127	    });
128	  },
129	
130	  removeTrack: (id: string) => {
131	    set((state) => {
132	      const track = state.tracks.find((t) => t.id === id);
133	      if (!track) return state;
134	      const removeSet = new Set(track.clipIds);
135	      const nextClips = Object.fromEntries(
136	        Object.entries(state.clips).filter(([k]) => !removeSet.has(k)),
137	      );
138	      return {
139	        tracks: state.tracks.filter((t) => t.id !== id),
140	        clips: nextClips,
141	      };
142	    });
143	  },
144	
145	  updateTrack: (id: string, patch: Partial<Omit<TrackModel, "id">>) => {
146	    set((state) => ({
147	      tracks: state.tracks.map((t) => (t.id === id ? { ...t, ...patch } : t)),
148	    }));
149	  },
150	
151	  reorderTrack: (id: string, toIndex: number) => {
152	    set((state) => {
153	      const fromIndex = state.tracks.findIndex((t) => t.id === id);
154	      if (fromIndex === -1) return state;
155	      const next = [...state.tracks];
156	      const moved = next.splice(fromIndex, 1)[0];
157	      if (moved === undefined) return state;
158	      next.splice(toIndex, 0, moved);
159	      return { tracks: next };
160	    });
161	  },
162	
163	  // Clip actions
164	  addClip: (clip: ClipModel) => {
165	    set((state) => {
166	      const nextClips = { ...state.clips, [clip.id]: clip };
167	      const tracks = state.tracks.map((t) =>
168	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, clip.id] } : t,
169	      );
170	      return { clips: nextClips, tracks };
171	    });
172	  },
173	
174	  removeClip: (id: string) => {
175	    set((state) => {
176	      const clip = state.clips[id];
177	      if (!clip) return state;
178	      const nextClips = Object.fromEntries(
179	        Object.entries(state.clips).filter(([k]) => k !== id),
180	      );
181	      const tracks = state.tracks.map((t) =>
182	        t.id === clip.trackId
183	          ? { ...t, clipIds: t.clipIds.filter((cid) => cid !== id) }
184	          : t,
185	      );
186	      return { clips: nextClips, tracks };
187	    });
188	  },
189	
190	  moveClip: (id: string, startTime: number, toTrackId?: string) => {
191	    set((state) => {
192	      const clip = state.clips[id];
193	      if (!clip) return state;
194	      const updatedClip = {
195	        ...clip,
196	        startTime,
197	        trackId: toTrackId ?? clip.trackId,
198	      };
199	      const nextClips = { ...state.clips, [id]: updatedClip };
200	
201	      let tracks = state.tracks;
202	      if (toTrackId !== undefined && toTrackId !== clip.trackId) {
203	        tracks = tracks.map((t) => {
204	          if (t.id === clip.trackId) {
205	            return { ...t, clipIds: t.clipIds.filter((cid) => cid !== id) };
206	          }
207	          if (t.id === toTrackId) {
208	            return { ...t, clipIds: [...t.clipIds, id] };
209	          }
210	          return t;
211	        });
212	      }
213	      return { clips: nextClips, tracks };
214	    });
215	  },
216	
217	  splitClip: (id: string, atTime: number): string | undefined => {
218	    const state = get();
219	    const clip = state.clips[id];
220	    if (!clip) return undefined;
221	
222	    const clipEnd = clip.startTime + clip.duration;
223	    if (atTime <= clip.startTime || atTime >= clipEnd) return undefined;
224	
225	    const leftDuration = atTime - clip.startTime;
226	    const rightDuration = clip.duration - leftDuration;
227	    const rightSourceOffset = clip.sourceOffset + leftDuration;
228	
229	    const newId = nextClipId();
230	
231	    const leftClip: ClipModel = { ...clip, duration: leftDuration };
232	    const rightClip: ClipModel = {
233	      ...clip,
234	      id: newId,
235	      startTime: atTime,
236	      sourceOffset: rightSourceOffset,
237	      duration: rightDuration,
238	    };
239	
240	    set((s) => {
241	      const nextClips = { ...s.clips, [id]: leftClip, [newId]: rightClip };
242	      const tracks = s.tracks.map((t) =>
243	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, newId] } : t,
244	      );
245	      return { clips: nextClips, tracks };
246	    });
247	
248	    return newId;
249	  },
250	
251	  trimClip: (id: string, newStart?: number, newEnd?: number) => {
252	    set((state) => {
253	      const clip = state.clips[id];
254	      if (!clip) return state;
255	
256	      let { startTime, sourceOffset, duration } = clip;
257	      const clipEnd = startTime + duration;
258	
259	      if (newStart !== undefined) {
260	        const delta = newStart - startTime;
261	        startTime = newStart;
262	        sourceOffset = sourceOffset + delta;
263	        duration = clipEnd - newStart;
264	      }
265	
266	      if (newEnd !== undefined) {
267	        duration = newEnd - startTime;
268	      }
269	
270	      return {
271	        clips: {
272	          ...state.clips,
273	          [id]: { ...clip, startTime, sourceOffset, duration },
274	        },
275	      };
276	    });
277	  },
278	
279	  duplicateClip: (id: string): string | undefined => {
280	    const state = get();
281	    const clip = state.clips[id];
282	    if (!clip) return undefined;
283	
284	    const newId = nextClipId();
285	    const duplicate: ClipModel = {
286	      ...clip,
287	      id: newId,
288	      startTime: clip.startTime + clip.duration,
289	    };
290	
291	    set((s) => {
292	      const nextClips = { ...s.clips, [newId]: duplicate };
293	      const tracks = s.tracks.map((t) =>
294	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, newId] } : t,
295	      );
296	      return { clips: { ...s.clips, ...nextClips }, tracks };
297	    });
298	
299	    return newId;
300	  },
301	
302	  // Selection
303	  setSelectedTrackIds: (ids: readonly string[]) => {
304	    set({ selectedTrackIds: ids });
305	  },
306	  setSelectedClipIds: (ids: readonly string[]) => {
307	    set({ selectedClipIds: ids });
308	  },
309	
310	  // Query
311	  queryClipsAtTime: (time: number): readonly ClipModel[] => {
312	    const state = get();
313	    const hasSolo = state.tracks.some((t) => t.solo);
314	    const activeTracks = new Set(
315	      state.tracks
316	        .filter((t) => {
317	          if (t.muted) return false;
318	          if (hasSolo && !t.solo) return false;
319	          return true;
320	        })
321	        .map((t) => t.id),
322	    );
323	
324	    return Object.values(state.clips).filter((clip) => {
325	      if (!activeTracks.has(clip.trackId)) return false;
326	      const clipEnd = clip.startTime + clip.duration;
327	      return time >= clip.startTime && time < clipEnd;
328	    });
329	  },
330	}));
