import { describe, it, expect, vi, beforeEach } from "vitest";
import type { TrackModel, ClipModel } from "@state/track/types";
import {
  renderArrangement,
  type ArrangementViewState,
  type RenderContext,
} from "./arrangement-renderer";

// -- Helpers ------------------------------------------------------------------

function createMockCtx(): CanvasRenderingContext2D {
  const ctx = {
    fillRect: vi.fn(),
    strokeRect: vi.fn(),
    fillText: vi.fn(),
    beginPath: vi.fn(),
    moveTo: vi.fn(),
    lineTo: vi.fn(),
    stroke: vi.fn(),
    save: vi.fn(),
    restore: vi.fn(),
    clearRect: vi.fn(),
    rect: vi.fn(),
    clip: vi.fn(),
    measureText: vi.fn().mockReturnValue({ width: 40 }),
    // Settable properties
    fillStyle: "",
    strokeStyle: "",
    lineWidth: 0,
    font: "",
    textBaseline: "" as CanvasTextBaseline,
    textAlign: "" as CanvasTextAlign,
    globalAlpha: 1,
  } as unknown as CanvasRenderingContext2D;
  return ctx;
}

function makeTrack(overrides: Partial<TrackModel> = {}): TrackModel {
  return {
    id: "track-1",
    name: "Track 1",
    type: "audio",
    color: "#0066ff",
    muted: false,
    solo: false,
    armed: false,
    volume: 1,
    pan: 0,
    clipIds: [],
    ...overrides,
  };
}

function makeClip(overrides: Partial<ClipModel> = {}): ClipModel {
  return {
    id: "clip-1",
    trackId: "track-1",
    sourceId: "src-1",
    startTime: 0,
    sourceOffset: 0,
    duration: 2,
    gain: 1,
    fadeIn: 0,
    fadeOut: 0,
    name: "Clip 1",
    ...overrides,
  };
}

const defaultView: ArrangementViewState = {
  scrollX: 0,
  scrollY: 0,
  pixelsPerSecond: 100,
  trackHeight: 64,
  headerWidth: 160,
};

function makeRenderContext(
  overrides: Partial<RenderContext> = {},
): RenderContext {
  return {
    ctx: createMockCtx(),
    width: 800,
    height: 400,
    view: defaultView,
    tracks: [],
    clips: {},
    selectedClipIds: [],
    cursorSeconds: 0,
    bpm: 120,
    ...overrides,
  };
}

// -- Tests --------------------------------------------------------------------

describe("arrangement-renderer", () => {
  describe("renderArrangement", () => {
    it("fills background with gray-900", () => {
