import { describe, it, expect, vi, beforeEach } from "vitest";
import type { TrackModel, ClipModel } from "@state/track/types";
import {
  renderArrangement,
  type ArrangementViewState,
  type RenderContext,
} from "./arrangement-renderer";

// -- Helpers ------------------------------------------------------------------

function createMockCtx(): CanvasRenderingContext2D {
  const ctx = {
    fillRect: vi.fn(),
    strokeRect: vi.fn(),
    fillText: vi.fn(),
    beginPath: vi.fn(),
    moveTo: vi.fn(),
    lineTo: vi.fn(),
    stroke: vi.fn(),
    save: vi.fn(),
    restore: vi.fn(),
    clearRect: vi.fn(),
    rect: vi.fn(),
    clip: vi.fn(),
    measureText: vi.fn().mockReturnValue({ width: 40 }),
    // Settable properties
    fillStyle: "",
    strokeStyle: "",
    lineWidth: 0,
    font: "",
    textBaseline: "" as CanvasTextBaseline,
    textAlign: "" as CanvasTextAlign,
    globalAlpha: 1,
  } as unknown as CanvasRenderingContext2D;
  return ctx;
}

function makeTrack(overrides: Partial<TrackModel> = {}): TrackModel {
  return {
    id: "track-1",
    name: "Track 1",
    type: "audio",
    color: "#0066ff",
    muted: false,
    solo: false,
    armed: false,
    volume: 1,
    pan: 0,
    clipIds: [],
    ...overrides,
  };
}

function makeClip(overrides: Partial<ClipModel> = {}): ClipModel {
  return {
    id: "clip-1",
    trackId: "track-1",
    sourceId: "src-1",
    startTime: 0,
    sourceOffset: 0,
    duration: 2,
    gain: 1,
    fadeIn: 0,
    fadeOut: 0,
    name: "Clip 1",
    ...overrides,
  };
}

const defaultView: ArrangementViewState = {
  scrollX: 0,
  scrollY: 0,
  pixelsPerSecond: 100,
  trackHeight: 64,
  headerWidth: 160,
};

function makeRenderContext(
  overrides: Partial<RenderContext> = {},
): RenderContext {
  return {
    ctx: createMockCtx(),
    width: 800,
    height: 400,
    view: defaultView,
    tracks: [],
    clips: {},
    selectedClipIds: [],
    cursorSeconds: 0,
    bpm: 120,
    ...overrides,
  };
}

// -- Tests --------------------------------------------------------------------

describe("arrangement-renderer", () => {
  describe("renderArrangement", () => {
    it("fills background with gray-900", () => {
      const rc = makeRenderContext();
      renderArrangement(rc);

      expect(rc.ctx.fillStyle).not.toBe("");
      expect(rc.ctx.fillRect).toHaveBeenCalledWith(0, 0, 800, 400);
    });

    it("draws the time ruler area", () => {
      const rc = makeRenderContext();
      renderArrangement(rc);

      // Should have drawn a ruler rectangle at the top
      const fillRectCalls = vi.mocked(rc.ctx.fillRect).mock.calls;
      // First call is background, subsequent calls include ruler
      expect(fillRectCalls.length).toBeGreaterThan(1);
    });

    it("draws vertical grid lines at beat positions", () => {
      const rc = makeRenderContext({ bpm: 120 });
      renderArrangement(rc);

      // At 120 BPM, seconds per beat = 0.5
      // With pixelsPerSecond=100, each beat is 50px apart
      const moveToArgs = vi.mocked(rc.ctx.moveTo).mock.calls;
      const lineToArgs = vi.mocked(rc.ctx.lineTo).mock.calls;

      // Should have at least some vertical lines
      expect(moveToArgs.length).toBeGreaterThan(0);
      expect(lineToArgs.length).toBeGreaterThan(0);
    });

    it("draws thicker lines on bar boundaries (every 4 beats)", () => {
      const rc = makeRenderContext({ bpm: 120 });
      renderArrangement(rc);

      // Check that lineWidth was set to different values for bars vs beats
      const ctx = rc.ctx;
      // We can verify save/restore calls bracket the grid drawing
      expect(ctx.save).toHaveBeenCalled();
      expect(ctx.restore).toHaveBeenCalled();
    });

    it("draws track lanes as horizontal bands", () => {
      const tracks = [
        makeTrack({ id: "t1", name: "Track 1" }),
        makeTrack({ id: "t2", name: "Track 2" }),
      ];
      const rc = makeRenderContext({ tracks });
      renderArrangement(rc);

      // Should draw lane separators
      const strokeCalls = vi.mocked(rc.ctx.stroke).mock.calls;
      expect(strokeCalls.length).toBeGreaterThan(0);
    });

    it("draws track headers with name and color strip", () => {
      const tracks = [
        makeTrack({ id: "t1", name: "Guitar", color: "#ff2d6f" }),
      ];
      const rc = makeRenderContext({ tracks });
      renderArrangement(rc);

      // Should draw the track name text
      const fillTextCalls = vi.mocked(rc.ctx.fillText).mock.calls;
      const drawnTexts = fillTextCalls.map(([text]) => text);
      expect(drawnTexts).toContain("Guitar");
    });

    it("draws mute indicator on muted tracks", () => {
      const tracks = [makeTrack({ id: "t1", name: "Bass", muted: true })];
      const rc = makeRenderContext({ tracks });
      renderArrangement(rc);

      const fillTextCalls = vi.mocked(rc.ctx.fillText).mock.calls;
      const drawnTexts = fillTextCalls.map(([text]) => text);
      expect(drawnTexts).toContain("M");
    });

    it("draws solo indicator on solo tracks", () => {
      const tracks = [makeTrack({ id: "t1", name: "Lead", solo: true })];
      const rc = makeRenderContext({ tracks });
      renderArrangement(rc);

      const fillTextCalls = vi.mocked(rc.ctx.fillText).mock.calls;
      const drawnTexts = fillTextCalls.map(([text]) => text);
      expect(drawnTexts).toContain("S");
    });

    it("draws clips as rectangles on the timeline", () => {
      const tracks = [makeTrack({ id: "t1", clipIds: ["c1"] })];
      const clips: Record<string, ClipModel> = {
        c1: makeClip({
          id: "c1",
          trackId: "t1",
          startTime: 1,
          duration: 2,
        }),
      };
      const rc = makeRenderContext({ tracks, clips });
      renderArrangement(rc);

      // Clip should be drawn as a filled rectangle
      const fillRectCalls = vi.mocked(rc.ctx.fillRect).mock.calls;
      // At pps=100 and startTime=1 with headerWidth=160:
      // x = 160 + (1 - 0) * 100 = 260, width = 2 * 100 = 200
      expect(fillRectCalls).toContainEqual(
        expect.arrayContaining([
          260,
          expect.any(Number),
          200,
          expect.any(Number),
        ]),
      );
    });

    it("draws clip name label", () => {
      const tracks = [makeTrack({ id: "t1", clipIds: ["c1"] })];
      const clips: Record<string, ClipModel> = {
        c1: makeClip({ id: "c1", trackId: "t1", name: "Vocal Take" }),
      };
      const rc = makeRenderContext({ tracks, clips });
      renderArrangement(rc);

      const fillTextCalls = vi.mocked(rc.ctx.fillText).mock.calls;
      const drawnTexts = fillTextCalls.map(([text]) => text);
      expect(drawnTexts).toContain("Vocal Take");
    });

    it("draws selected clips with white border", () => {
      const tracks = [makeTrack({ id: "t1", clipIds: ["c1"] })];
      const clips: Record<string, ClipModel> = {
        c1: makeClip({ id: "c1", trackId: "t1" }),
      };
      const rc = makeRenderContext({
        tracks,
        clips,
        selectedClipIds: ["c1"],
      });
      renderArrangement(rc);

      // Should have set strokeStyle to white for the selected clip border
      expect(rc.ctx.strokeRect).toHaveBeenCalled();
    });

    it("draws the playhead as a vertical red line", () => {
      const rc = makeRenderContext({ cursorSeconds: 2 });
      renderArrangement(rc);

      // Playhead at 2s with pps=100, headerWidth=160: x = 160 + 2*100 = 360
      const moveToArgs = vi.mocked(rc.ctx.moveTo).mock.calls;
      const lineToArgs = vi.mocked(rc.ctx.lineTo).mock.calls;

      // Check that a line is drawn at x=360
      const playheadMoves = moveToArgs.filter(([x]) => x === 360);
      expect(playheadMoves.length).toBeGreaterThan(0);

      const playheadLines = lineToArgs.filter(([x]) => x === 360);
      expect(playheadLines.length).toBeGreaterThan(0);
    });

    it("draws bar numbers in the time ruler", () => {
      const rc = makeRenderContext({ bpm: 120 });
      renderArrangement(rc);

      const fillTextCalls = vi.mocked(rc.ctx.fillText).mock.calls;
      const drawnTexts = fillTextCalls.map(([text]) => text);
      // Should contain bar number labels like "1", "2", etc.
      expect(drawnTexts).toContain("1");
    });

    it("respects scrollX offset for grid and clips", () => {
      const view: ArrangementViewState = {
        ...defaultView,
        scrollX: 2, // scrolled 2 seconds to the right
      };
      const tracks = [makeTrack({ id: "t1", clipIds: ["c1"] })];
      const clips: Record<string, ClipModel> = {
        c1: makeClip({
          id: "c1",
          trackId: "t1",
          startTime: 3,
          duration: 1,
        }),
      };
      const rc = makeRenderContext({ view, tracks, clips });
      renderArrangement(rc);

      // Clip at startTime=3 with scrollX=2, pps=100, headerWidth=160:
      // x = 160 + (3 - 2) * 100 = 260
      const fillRectCalls = vi.mocked(rc.ctx.fillRect).mock.calls;
      expect(fillRectCalls).toContainEqual(
        expect.arrayContaining([
          260,
          expect.any(Number),
          100,
          expect.any(Number),
        ]),
      );
    });

    it("respects scrollY offset for tracks", () => {
      const view: ArrangementViewState = {
        ...defaultView,
        scrollY: 30,
      };
      const tracks = [makeTrack({ id: "t1", name: "Shifted Track" })];
      const rc = makeRenderContext({ view, tracks });
      renderArrangement(rc);

      // Track header text should be offset by scrollY
      const fillTextCalls = vi.mocked(rc.ctx.fillText).mock.calls;
      const shiftedCall = fillTextCalls.find(
        ([text]) => text === "Shifted Track",
      );
      expect(shiftedCall).toBeDefined();
    });

    it("adjusts grid density when zoomed out", () => {
      const view: ArrangementViewState = {
        ...defaultView,
        pixelsPerSecond: 20, // zoomed way out
      };
      const rc = makeRenderContext({ view });
      renderArrangement(rc);

      // Should still draw grid lines without errors
      expect(rc.ctx.stroke).toHaveBeenCalled();
    });

    it("does not crash with empty tracks and clips", () => {
      const rc = makeRenderContext({ tracks: [], clips: {} });
      expect(() => renderArrangement(rc)).not.toThrow();
    });

    it("does not crash when clip references missing track", () => {
      const tracks = [makeTrack({ id: "t1", clipIds: ["c1"] })];
      const clips: Record<string, ClipModel> = {
